function ClmEvidenceTimeUnits() {}
ClmEvidenceTimeUnits.dataBinding = "/ds/EnterVariableData/TrialNotice/clmEvidenceTimeUnits";
ClmEvidenceTimeUnits.tabIndex = __tabIdx++;
ClmEvidenceTimeUnits.helpText = "Select unit time";
ClmEvidenceTimeUnits.mandatoryOn = [ClmEvidenceTime.dataBinding];
ClmEvidenceTimeUnits.isMandatory = function()
{	var val = Services.getValue(ClmEvidenceTime.dataBinding);
	return( null != val && "" != val );
}	
ClmEvidenceTimeUnits.isTemporary = function(){  return true; }	
ClmEvidenceTimeUnits.enableOn = [ClmEvidenceTime.dataBinding];
ClmEvidenceTimeUnits.isEnabled = function(){ return ClmEvidenceTime.isEnabled();}
ClmEvidenceTimeUnits.logicOn = [ClmEvidenceTime.dataBinding];
ClmEvidenceTimeUnits.logic = function()
{	if(!ClmEvidenceTime.isEnabled())
	Services.setValue(ClmEvidenceTimeUnits.dataBinding,"");			
}
